+//! ELF64 program header parsing.
+//!
+//! Program headers describe segments used for loading the executable.
+
+use super::{ElfError, ElfResult};
+
+/// Program header type.
+#[derive(Debug, Clone, Copy, PartialEq, Eq)]
+pub enum ProgramType {
+    /// Unused entry
+    Null,
+    /// Loadable segment
+    Load,
+    /// Dynamic linking information
+    Dynamic,
+    /// Interpreter path
+    Interp,
+    /// Auxiliary information
+    Note,
+    /// Reserved (unused)
+    Shlib,
+    /// Program header table
+    Phdr,
+    /// Thread-local storage template
+    Tls,
+    /// GNU stack permissions
+    GnuStack,
+    /// GNU relocation read-only
+    GnuRelro,
+    /// GNU property
+    GnuProperty,
+    /// GNU exception handling
+    GnuEhFrame,
+    /// Unknown type
+    Unknown(u32),
+}
+
+impl From<u32> for ProgramType {
+    fn from(value: u32) -> Self {
+        match value {
+            0 => Self::Null,
+            1 => Self::Load,
+            2 => Self::Dynamic,
+            3 => Self::Interp,
+            4 => Self::Note,
+            5 => Self::Shlib,
+            6 => Self::Phdr,
+            7 => Self::Tls,
+            0x6474_e550 => Self::GnuEhFrame,
+            0x6474_e551 => Self::GnuStack,
+            0x6474_e552 => Self::GnuRelro,
+            0x6474_e553 => Self::GnuProperty,
+            other => Self::Unknown(other),
+        }
+    }
+}
+
+/// Program header flags.
+#[derive(Debug, Clone, Copy, PartialEq, Eq)]
+pub struct ProgramFlags(pub u32);
+
+impl ProgramFlags {
+    /// Execute permission
+    pub const PF_X: u32 = 0x1;
+    /// Write permission
+    pub const PF_W: u32 = 0x2;
+    /// Read permission
+    pub const PF_R: u32 = 0x4;
+
+    /// Check if executable.
+    pub fn is_executable(self) -> bool {
+        self.0 & Self::PF_X != 0
+    }
+
+    /// Check if writable.
+    pub fn is_writable(self) -> bool {
+        self.0 & Self::PF_W != 0
+    }
+
+    /// Check if readable.
+    pub fn is_readable(self) -> bool {
+        self.0 & Self::PF_R != 0
+    }
+
+    /// Convert to mmap protection flags.
+    ///
+    /// Returns a bitmask suitable for mmap's prot argument:
+    /// - 0x1 = PROT_READ
+    /// - 0x2 = PROT_WRITE
+    /// - 0x4 = PROT_EXEC
+    pub fn to_mmap_prot(self) -> i32 {
+        const PROT_READ: i32 = 0x1;
+        const PROT_WRITE: i32 = 0x2;
+        const PROT_EXEC: i32 = 0x4;
+
+        let mut prot = 0i32;
+        if self.is_readable() {
+            prot |= PROT_READ;
+        }
+        if self.is_writable() {
+            prot |= PROT_WRITE;
+        }
+        if self.is_executable() {
+            prot |= PROT_EXEC;
+        }
+        prot
+    }
+}
